<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Conway's Game of Life</title>
  <style>
    :root {
      --bg-color: #1a1a2e;
      --grid-bg: #16213e;
      --cell-color: #0f3460;
      --live-cell: #e94560;
      --text-color: #ffffff;
      --btn-bg: #0f3460;
      --btn-hover: #1a4b8c;
    }

    body {
      margin: 0;
      padding: 20px;
      background-color: var(--bg-color);
      color: var(--text-color);
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      min-height: 100vh;
    }

    h1 {
      margin-bottom: 20px;
      text-align: center;
      font-weight: 300;
      letter-spacing: 2px;
    }

    .controls {
      display: flex;
      gap: 15px;
      margin-bottom: 20px;
      flex-wrap: wrap;
      justify-content: center;
    }

    button {
      background-color: var(--btn-bg);
      color: white;
      border: none;
      padding: 10px 20px;
      font-size: 16px;
      border-radius: 5px;
      cursor: pointer;
      transition: all 0.3s ease;
      box-shadow: 0 4px 6px rgba(0,0,0,0.3);
    }

    button:hover {
      background-color: var(--btn-hover);
      transform: translateY(-2px);
    }

    button:active {
      transform: translateY(1px);
    }

    #life-container {
      position: relative;
      box-shadow: 0 0 20px rgba(0,0,0,0.5);
      border-radius: 8px;
      overflow: hidden;
    }

    canvas#life {
      background-color: var(--grid-bg);
      cursor: crosshair;
      display: block;
    }

    .info {
      margin-top: 15px;
      font-size: 14px;
      color: #aaa;
      text-align: center;
    }
  </style>
</head>
<body>
  <h1>Conway's Game of Life</h1>

  <div class="controls">
    <button id="step">Step</button>
    <button id="play">Play</button>
    <button id="random">Randomize</button>
    <button id="clear">Clear</button>
  </div>

  <div id="life-container">
    <canvas id="life"></canvas>
  </div>

  <div class="info">
    Click and drag to paint cells • B3/S23 Rules • Dead Edges
  </div>

  <script>
    // Game of Life Implementation
    const canvas = document.getElementById('life');
    const ctx = canvas.getContext('2d');

    // Configuration
    const CELL_SIZE = 10;
    const GRID_WIDTH = 60;  // At least 40 as required
    const GRID_HEIGHT = 60; // At least 40 as required

    // Set canvas size based on grid and cell size
    canvas.width = GRID_WIDTH * CELL_SIZE;
    canvas.height = GRID_HEIGHT * CELL_SIZE;

    // Create the grid (2D array)
    let grid = [];

    // Initialize empty grid
    function createGrid() {
      const newGrid = [];
      for (let y = 0; y < GRID_HEIGHT; y++) {
        const row = [];
        for (let x = 0; x < GRID_WIDTH; x++) {
          row.push(0);
        }
        newGrid.push(row);
      }
      return newGrid;
    }

    // Initialize grid
    function init() {
      grid = createGrid();
      draw();
    }

    // Count neighbors for a cell at (x, y)
    function countNeighbors(x, y) {
      let count = 0;

      // Check all 8 neighboring cells
      for (let dy = -1; dy <= 1; dy++) {
        for (let dx = -1; dx <= 1; dx++) {
          if (dx === 0 && dy === 0) continue; // Skip self

          const nx = x + dx;
          const ny = y + dy;

          // Dead edges: out-of-bounds cells count as 0
          if (nx >= 0 && nx < GRID_WIDTH && ny >= 0 && ny < GRID_HEIGHT) {
            count += grid[ny][nx];
          }
        }
      }

      return count;
    }

    // Compute next generation using B3/S23 rules
    function computeNextGeneration() {
      const nextGrid = [];

      for (let y = 0; y < GRID_HEIGHT; y++) {
        const row = [];
        for (let x = 0; x < GRID_WIDTH; x++) {
          const neighbors = countNeighbors(x, y);
          const isAlive = grid[y][x] === 1;

          // B3/S23 rules:
          // Dead cell with exactly 3 live neighbors becomes alive
          // Live cell with 2 or 3 live neighbors survives
          if (isAlive) {
            row.push((neighbors === 2 || neighbors === 3) ? 1 : 0);
          } else {
            row.push(neighbors === 3 ? 1 : 0);
          }
        }
        nextGrid.push(row);
      }

      grid = nextGrid;
    }

    // Draw the grid
    function draw() {
      // Clear canvas with background color
      ctx.fillStyle = '#16213e';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Draw live cells
      ctx.fillStyle = '#e94560';

      for (let y = 0; y < GRID_HEIGHT; y++) {
        for (let x = 0; x < GRID_WIDTH; x++) {
          if (grid[y][x] === 1) {
            // Draw cell with a small gap for grid effect
            const padding = 1;
            ctx.fillRect(
              x * CELL_SIZE + padding, 
              y * CELL_SIZE + padding, 
              CELL_SIZE - padding * 2, 
              CELL_SIZE - padding * 2
            );
          }
        }
      }
    }

    // Step function (advance one generation)
    function step() {
      computeNextGeneration();
      draw();
    }

    // Clear all cells
    function clearGrid() {
      grid = createGrid();
      draw();
    }

    // Randomize cells
    function randomize() {
      for (let y = 0; y < GRID_HEIGHT; y++) {
        for (let x = 0; x < GRID_WIDTH; x++) {
          grid[y][x] = Math.random() > 0.85 ? 1 : 0; // ~15% chance of being alive
        }
      }
      draw();
    }

    // Mouse interaction variables
    let isDrawing = false;
    let drawMode = 1; // 1 for adding cells, 0 for removing cells

    // Handle mouse events for painting cells
    function handleMouse(e) {
      const rect = canvas.getBoundingClientRect();
      const mouseX = e.clientX - rect.left;
      const mouseY = e.clientY - rect.top;

      const x = Math.floor(mouseX / CELL_SIZE);
      const y = Math.floor(mouseY / CELL_SIZE);

      // Check bounds
      if (x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
        grid[y][x] = drawMode;
        draw();
      }
    }

    // Add event listeners for mouse interaction
    canvas.addEventListener('mousedown', (e) => {
      isDrawing = true;
      handleMouse(e);

      // Determine if we're adding or removing based on current cell state
      const rect = canvas.getBoundingClientRect();
      const mouseX = e.clientX - rect.left;
      const mouseY = e.clientY - rect.top;
      const x = Math.floor(mouseX / CELL_SIZE);
      const y = Math.floor(mouseY / CELL_SIZE);

      if (x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
        drawMode = grid[y][x] ? 0 : 1;
      }
    });

    canvas.addEventListener('mousemove', (e) => {
      if (isDrawing) {
        handleMouse(e);
      }
    });

    window.addEventListener('mouseup', () => {
      isDrawing = false;
    });

    // Setup the API on window
    window.life = {
      w: GRID_WIDTH,
      h: GRID_HEIGHT,

      get(x, y) {
        if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) {
          return 0; // Out of bounds counts as dead
        }
        return grid[y][x];
      },

      set(x, y, v) {
        if (x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
          grid[y][x] = v ? 1 : 0;
          draw();
        }
      },

      step() {
        step();
      },

      clear() {
        clearGrid();
      }
    };

    // Initialize the game
    init();

    // Button event listeners
    document.getElementById('step').addEventListener('click', () => {
      step();
    });

    let isPlaying = false;
    let playInterval = null;

    document.getElementById('play').addEventListener('click', () => {
      if (isPlaying) {
        clearInterval(playInterval);
        isPlaying = false;
        document.getElementById('play').textContent = 'Play';
      } else {
        isPlaying = true;
        document.getElementById('play').textContent = 'Stop';
        playInterval = setInterval(step, 100); // Run at 10 FPS
      }
    });

    document.getElementById('random').addEventListener('click', () => {
      randomize();
    });

    document.getElementById('clear').addEventListener('click', () => {
      clearGrid();
    });
  </script>
</body>
</html>
